Here's a solid pattern for testing `DataFetcher` with MSTest:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellation()
    {
        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // MSTest-level safety net — fails if test hangs
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Reusable fake handler — no external mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode,
            TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken); // throws if cancelled

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key techniques:**

- **`MockHttpMessageHandler`** — subclass `HttpMessageHandler` to control responses without external libraries. The `delay` parameter simulates slow servers.
- **`CancellationTokenSource` with timeout** — proves your code actually forwards the token and responds to cancellation.
- **`[Timeout(3000)]`** — MSTest's built-in safety net; fails the test if it hangs beyond 3 seconds instead of blocking CI forever.
- **`await Assert.ThrowsExceptionAsync<T>`** — the correct pattern for asserting exceptions from async methods (never use `.Result` or `.Wait()`).
